import React from "react";

export const DashboardContent = (props) => {
  const data = props.data;
  return (
    <div>
      {props.pagecontent === "none" ? (
        <div className="w-full h-[100vh] flex justify-center items-center">
          <div
            align="center"
            className="w-[90%] p-[10px] bg-[#845EC2] rounded-md"
          >
            <h1 className="text-white text-[20px]">None</h1>
          </div>
        </div>
      ) : (
        <div className="w-[100%] flex flex-col justify-center items-center">
          <div className="flex flex-row justify-center items-center w-[90%] bg-[#845EC2] mt-[20px] mb-[20px] rounded-md">
            <div align="center" className="w-[90%] text-white text-[20px] p-[10px]">
              {data.map((item) => {
                return item.id === props.pagecontent ? (
                  <div>{item.title}</div>
                ) : null;
              })}
            </div>
            <div className="w-[10%] text-white text-[18px]">
            <i className="fa-solid fa-trash"></i>
            </div>
          </div>
          <div className="bg-white w-[90%] h-[85vh] rounded-md flex flex-row">
            <div className="w-[2%]"></div>
            <div className="menucenter w-[96%] mt-[10px] mb-[10px] overflow-y-auto  focus-visible:outline-none" contenteditable="true">
              {data.map((item) => {
                  return item.id === props.pagecontent ? (
                    <div>{item.content}</div>
                  ) : null;
                })}
            </div>
          </div>
        </div>
      )}

      {/* {props.pagecontent === "none" ? (
        <div>None</div>
      ) : (
        data.map((item) => {
          return item.id === props.pagecontent ? (
            <div>{item.content}</div>
          ) : null;
        })
      )} */}
    </div>
  );
};
